import { useState } from "react";

import {
  Box,
  Button,
  Container,
  Paper,
  TextField,
  Typography,
} from "@mui/material";

import "./App.css";

function App() {
  const [id, setId] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");

  const handleLogin = async () => {
    try {
      const response = await fetch("http://127.0.0.1:5000/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          id,
          password,
        }),
      });

      const data = await response.json();

      if (data.success) {
        setMessage("로그인 성공!");
      } else {
        setMessage(data.message);
      }
    } catch (error) {
      setMessage("서버 오류");
    }
  };

  return (
    <Box className="background">
      <Container
        maxWidth="xs"
        className="container-wrapper"
      >
        <Paper elevation={3} className="login-card">
            <img
              src="public/klas_logo.png"
              alt="KLAS Logo"
              className="logo"
            />

          <Typography align="center" className="subtitle-main">
              종합정보서비스(KLAS)
          </Typography>

          <Typography align="center" className="subtitle-sub">
              계정으로 로그인해주세요.
          </Typography>


          <Typography
            variant="h4"
            align="center"
            className="title"
          >
            LOGIN
          </Typography>

          <TextField
            fullWidth
            label="학번"
            margin="normal"
            value={id}
            onChange={(e) => setId(e.target.value)}
          />

          <TextField
            fullWidth
            type="password"
            label="비밀번호"
            margin="normal"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <Button
            fullWidth
            variant="contained"
            className="login-button"
            onClick={handleLogin}
          >
            로그인
          </Button>

          <Typography
            align="center"
            className="message"
          >
            {message}
          </Typography>
        </Paper>
      </Container>
    </Box>
  );
}

export default App;
